#include <stdio.h>
#include <math.h>
int gcd(int a, int b) { return b ? gcd(b, a % b) : a; }
int main() { int t; scanf("%d", &t); while (t--) { int n; scanf("%d", &n); int arr[n]; for (int i = 0; i < n; i++) scanf("%d", &arr[i]); int g = arr[0]; for (int i = 1; i < n; i++) g = gcd(g, arr[i]); int ans = 0; for (int i = 0; i < n; i++) ans += arr[i] / g - 1; printf("%d\n", ans); } return 0; }

