import java.util.Scanner;
public class Main { public static int gcd(int a, int b) { return b == 0 ? a : gcd(b, a % b); }
public static void main(String[] args) { Scanner sc = new Scanner(System.in); int t = sc.nextInt(); while (t-- > 0) { int n = sc.nextInt(); int[] arr = new int[n]; for (int i = 0; i < n; i++) arr[i] = sc.nextInt(); int g = arr[0]; for (int i = 1; i < n; i++) g = gcd(g, arr[i]); int ans = 0; for (int i = 0; i < n; i++) ans += arr[i] / g - 1; System.out.println(ans); } } }

code.JavaScript:
const readline = require('readline').createInterface({ input: process.stdin, output: process.stdout });
let i = 0;
let t;
let n;
let arr;
readline.on('line', line => {
    if (i == 0) {
        t = parseInt(line);
        i++;
    } else if (i == 1) {
        n = parseInt(line);
        i++;
    } else {
        arr = line.split(' ').map(x => parseInt(x));
        let g = arr[0];
        for (let j = 1; j < n; j++) g = gcd(g, arr[j]);
        let ans = 0;
        for (let j = 0; j < n; j++) ans += Math.floor(arr[j] / g) - 1;
        console.log(ans);
        i = 1;
        t--;
        if (t == 0) process.exit();
    }
});
function gcd(a, b) { return b == 0 ? a : gcd(b, a % b); }
